/**
 * Specs Inc. 2026
 * waterMask.ts – per-city LAND/WATER grids for keeping card markers off the ocean.
 *
 * !!! GENERATED BY tools/generate_water_mask.py FROM THE BAKED <City>_L-1.png !!!
 * Do not hand-edit. Re-run the tool (no network) to refresh. Each mask is a square
 * `spanDeg`-wide window centered on the city: `rows[i]` runs NORTH(0)->SOUTH, each
 * char WEST(0)->EAST, '1' = land, '0' = water. isLandAt() maps a latLng to a cell
 * and FAILS OPEN (returns land) for unknown cities or out-of-window points, so a
 * marker is never lost to a missing mask.
 */
import { LatLng } from "./GeoMath";

/** One city's land/water grid over a square window centered on the city. */
export interface CityWaterMask {
  name: string;
  centerLatLng: LatLng;
  /** Longitude/latitude width of the (square) window, degrees. */
  spanDeg: number;
  /** Grid resolution per side. */
  res: number;
  /** res row strings, NORTH->SOUTH; each char WEST->EAST, '1' land / '0' water. */
  rows: string[];
}

