const BY_NAME: { [name: string]: CityWaterMask } = {};
for (const m of CITY_WATER_MASKS) BY_NAME[m.name.toLowerCase()] = m;

/**
 * True when `latLng` is on LAND for `cityName` (the inverse of the bake-side
 * grid mapping: row NORTH->SOUTH, col WEST->EAST). FAILS OPEN — returns true for
 * an unknown city or a point outside the mask window — so markers are never
 * dropped just because the mask doesn't cover them.
 */
export function isLandAt(cityName: string, latLng: LatLng): boolean {
  const m = BY_NAME[(cityName || "").toLowerCase()];
  if (!m) return true;
  const fLat = 0.5 - (latLng.lat - m.centerLatLng.lat) / m.spanDeg;
  const fLng = (latLng.lng - m.centerLatLng.lng) / m.spanDeg + 0.5;
  const i = Math.floor(fLat * m.res);
  const j = Math.floor(fLng * m.res);
  if (i < 0 || i >= m.res || j < 0 || j >= m.res) return true;
  return m.rows[i].charAt(j) === "1";
}
